import { c as _export_sfc, Q as openBlock, j as createElementBlock, m as createStaticVNode } from "./chunks/framework.OPxAocOb.js";
const __pageData = JSON.parse('{"title":"How aglang Works","description":"","frontmatter":{},"headers":[],"relativePath":"how-it-works.md","filePath":"how-it-works.md"}');
